  1→/**
  2→ * Repository Actions Hook — repo registration, workspace creation, and git clone.
  3→ *
  4→ * Extracted from MainLayout to keep the layout component focused on
  5→ * orchestrating sidebar/content panels and mounting modals.
  6→ *
  7→ * Owns all state and logic for:
  8→ * - Opening a local project (native dialog + addRepo + auto-create workspace)
  9→ * - Cloning a GitHub repo (validate URL, git clone, register, create workspace)
 10→ * - Creating workspaces from the new-workspace modal
 11→ * - 409 conflict handling when registering a repo that already exists
 12→ * - Generation counter to prevent stale clone invocations from mutating state
 13→ */
 14→
 15→import { useState, useRef, useCallback } from "react";
 16→import { toast } from "sonner";
 17→import type { Repository } from "@/features/repository/types";
 18→import { useCreateWorkspace } from "@/features/workspace/api";
 19→import { useAddRepo } from "@/features/repository/api";
 20→import { native } from "@/platform";
 21→import { capabilities } from "@/platform/capabilities";
 22→import { getBackendUrl } from "@/shared/config/api.config";
 23→import { extractRepoNameFromUrl } from "@/shared/lib/utils";
 24→import { getErrorMessage } from "@shared/lib/errors";
 25→
 26→interface UseRepoActionsOptions {
 27→  selectWorkspace: (id: string | null) => void;
 28→  openNewWorkspaceModal: () => void;
 29→  closeNewWorkspaceModal: () => void;
 30→}
 31→
 32→export function useRepoActions({
 33→  selectWorkspace,
 34→  openNewWorkspaceModal,
 35→  closeNewWorkspaceModal,
 36→}: UseRepoActionsOptions) {
 37→  // Mutations
 38→  const createWorkspaceMutation = useCreateWorkspace();
 39→  const addRepoMutation = useAddRepo();
 40→
 41→  // New-workspace modal state
 42→  const [selectedRepoId, setSelectedRepoId] = useState("");
 43→  const [creating, setCreating] = useState(false);
 44→
 45→  // Clone modal state
 46→  const [cloning, setCloning] = useState(false);
 47→  const [showCloneModal, setShowCloneModal] = useState(false);
 48→  const [cloneError, setCloneError] = useState<string | null>(null);
 49→  const [cloneStatus, setCloneStatus] = useState<string | null>(null);
 50→
 51→  // Generation counter: prevents stale clone invocations from mutating state.
 52→  // Each call to handleCloneRepository captures its generation; if the counter
 53→  // advances (via close or a new clone), earlier invocations bail out.
 54→  const cloneGenerationRef = useRef(0);
 55→
 56→  /** Reset all clone modal state to idle. */
 57→  function resetCloneState() {
 58→    setShowCloneModal(false);
 59→    setCloneError(null);
 60→    setCloneStatus(null);
 61→    setCloning(false);
